patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -9,7 +9,7 @@ module priority_encoder(
   output reg [2:0] priority
 );

-  always @(request[3] or request[2])
+  always @(request[7] or request[6] or request[5] or request[4] or request[3] or request[2] or request[1] or request[0])
     casez(request)
       8'b1xxxxxxx: priority = 3'd7;
       8'b01xxxxxx: priority = 3'd6;

before_code:
module priority_encoder(
  input [7:0] request,
  output reg [2:0] priority
);

  always @(request[3] or request[2])
    casez(request)
      8'b1xxxxxxx: priority = 3'd7;
      8'b01xxxxxx: priority = 3'd6;
      8'b001xxxxx: priority = 3'd5;
      8'b0001xxxx: priority = 3'd4;
      8'b00001xxx: priority = 3'd3;
      8'b000001xx: priority = 3'd2;
      8'b0000001x: priority = 3'd1;
      8'b00000001: priority = 3'd0;
      default: priority = 3'd0;
    endcase

endmodule

after_code:
module priority_encoder(
  input [7:0] request,
  output reg [2:0] priority
);

  always @(request[7] or request[6] or request[5] or request[4] or request[3] or request[2] or request[1] or request[0])
    casez(request)
      8'b1xxxxxxx: priority = 3'd7;
      8'b01xxxxxx: priority = 3'd6;
      8'b001xxxxx: priority = 3'd5;
      8'b0001xxxx: priority = 3'd4;
      8'b00001xxx: priority = 3'd3;
      8'b000001xx: priority = 3'd2;
      8'b0000001x: priority = 3'd1;
      8'b00000001: priority = 3'd0;
      default: priority = 3'd0;
    endcase

endmodule
